#include <OneWire.h>
#include <DallasTemperature.h>
#include <Wire.h>
#include <Adafruit_SSD1306.h>
#define OW_PIN 2
#define SSR_PIN 8
#define FAULT_IN_PIN 6
#define WARN_TEMP 70.0f
#define FAULT_TEMP 90.0f
#define MAX_RATE 0.5f
OneWire ow(OW_PIN); DallasTemperature ds(&ow);
Adafruit_SSD1306 oled(128,64,&Wire,-1);
float g_prevT=0;
bool runaway_rate_detector(float T,float dt,float*prevT,float maxR,float faultT){
  float rate=(dt>0.001f)?(T-*prevT)/dt:0.0f;
  *prevT=T;
  return(rate>maxR||T>faultT);
}
void initHardware(){
  ds.begin();pinMode(SSR_PIN,OUTPUT);pinMode(FAULT_IN_PIN,INPUT_PULLUP);
  oled.begin(SSD1306_SWITCHCAPVCC,0x3C);oled.clearDisplay();
  Serial.begin(9600);
}
float readTemperatureSensor(){
  ds.requestTemperatures();return ds.getTempCByIndex(0);
}
void coolingSSRControl(float T){
  if(T>WARN_TEMP){int d=(int)constrain(5*(T-WARN_TEMP),0,255);analogWrite(SSR_PIN,d);}
  else analogWrite(SSR_PIN,0);
}
void updateOLEDDisplay(float T,float rate,bool fault){
  oled.clearDisplay();oled.setTextSize(1);oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,0);oled.print("T:");oled.print(T,1);oled.print("C");
  oled.setCursor(0,12);oled.print("dT/dt:");oled.print(rate,3);oled.print("C/s");
  oled.setCursor(0,24);oled.print(fault?"!! FAULT-RUNAWAY !!":(T>WARN_TEMP?"WARNING":"OK"));
  oled.display();
}
void checkHardwareInterlock(){
  if(digitalRead(FAULT_IN_PIN)==LOW){
    analogWrite(SSR_PIN,255);Serial.println("HW_FAULT:INTERLOCK");
  }
}
void setup(){initHardware();g_prevT=readTemperatureSensor();}
void loop(){
  static unsigned long prev=0;unsigned long now=millis();
  if(now-prev<500)return;prev=now;
  float dt=(now-prev)/1000.0f;float T=readTemperatureSensor();
  bool fault=runaway_rate_detector(T,0.5f,&g_prevT,MAX_RATE,FAULT_TEMP);
  if(fault){analogWrite(SSR_PIN,255);Serial.println("SW_FAULT:RUNAWAY");}
  coolingSSRControl(T);
  checkHardwareInterlock();
  float rate=(T-g_prevT)/0.5f;
  updateOLEDDisplay(T,rate,fault);
  Serial.print("T=");Serial.print(T,2);Serial.print(" rate=");Serial.println(rate,3);
}
